import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function DriverDashboard() {
  const [tasks, setTasks] = useState([]);
  const navigate = useNavigate();

  const getTasks = async () => {
    try {
      const res = await axios.get(
        "http://localhost:3000/api/driver/today-task"
      );

      setTasks(res.data.requests);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getTasks();
  }, []);

  return (
    <div className="min-h-screen bg-[#4CBB17]/10 p-8">
              <div className="mb-8 bg-[#4CBB17]/40 px-6 ">
                <div className="flex items-center justify-between">
      
                  {/* Logo + Title */}
                  <div >
                    <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
                      <img
                        src="garbageVehicle.jpeg"
                        alt=""
                        className="w-16 h-16 object-contain"
                      />
                      CleanTrack
                    </h1>
      
                    <p className="text-gray-900 p-2">
                      Smart Waste Management Control Center
                    </p>
                  </div>
      
                  {/* Navigation Links */}
                  <div className="flex items-center gap-8 text-lg font-semibold">
      
                    <Link
                      to="/send-otp"
                      className="text-green-900 hover:text-white-900 transition-all duration-300 hover:scale-105"
                    >
                      Create User
                    </Link>
      
                    <button
                      onClick={() => {
                        setShowRequests(!showRequests);
                        fetchRequests();
                      }}
                      className="text-green-900 hover:text-green-900 transition-all duration-300 hover:scale-105"
                    >
                      View Requests
                    </button>
      
                  </div>
                </div>
              </div>
      <div className="text-center mb-10">
        <h1 className="text-5xl font-extrabold text-green-900">
          Today's Tasks
        </h1>
      </div>

      {tasks.length === 0 ? (
        <div className="bg-white p-10 rounded-2xl text-center shadow">
          <h2 className="text-2xl font-bold text-gray-500">
            No Tasks Available
          </h2>
        </div>
      ) : (
        <div className="space-y-5">
          {tasks.map((task) => (
            <div
              key={task._id}
              className="bg-white rounded-2xl shadow-lg p-6 flex justify-between items-center"
            >
              <div>
                <p className="font-bold text-gray-700">
                  Request ID :
                </p>
                <p className="text-sm text-gray-500 mb-2">
                  {task._id}
                </p>

                <p className="font-bold text-green-700">
                  📍 {task.location?.location}
                </p>

                <p className="mt-2 text-gray-600">
                  Created :
                  {" "}
                  {new Date(task.createdAt).toLocaleString()}
                </p>
              </div>

             <button
  onClick={() =>
    window.open(
      `/driver-route/${task._id}`,
      "_blank"
    )
  }
  className="bg-green-600 hover:bg-green-700 text-white px-8 py-3 rounded-xl font-semibold"
>
  Start Route
</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
